total_employee_count = #{totalEmployeeCount}, disabled_employee_count = #{disabledEmployeeCount}, required_ratio = #{requiredRatio}, calculated_amount = #{calculatedAmount}, reduction_amount = #{reductionAmount}, payable_amount = #{payableAmount}, paid_amount = #{paidAmount}, payment_status = #{paymentStatus}, status = #{status}, confirm_time = #{confirmTime},
